// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract CounterVault {
    address public owner;
    uint256 private _counter;
    bool private locked;

    event CounterUpdated(address indexed owner, uint256 newCounter);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    // Transfer ownership to a new owner
    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "New owner cannot be zero address");
        owner = newOwner;
    }

    // Renounce ownership
    function renounceOwnership() public onlyOwner {
        owner = address(0);
    }

    // Increment counter using inline assembly for gas efficiency
    function incrementCounter() public onlyOwner noReentrancy {
        unchecked {
            _counter += 1;
        }
        emit CounterUpdated(owner, _counter);
    }

    function getCounter() public view returns (uint256) {
        return _counter;
    }

    // Example of Checks-Effects-Interactions pattern
    function setValue(uint256 newValue) public onlyOwner {
        require(newValue >= 0, "Value cannot be negative");
        _counter = newValue;
        emit CounterUpdated(owner, _counter);
    }
}
