    address public owner;
    uint256 private _counter;

    event CounterUpdated(address indexed owner, uint256 newCounter);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    // Transfer ownership to a new owner
    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "New owner cannot be zero address");
        owner = newOwner;
    }

    // Renounce ownership
    function renounceOwnership() public onlyOwner {
        owner = address(0);
    }

    // Increment counter using inline assembly for gas efficiency
    function incrementCounter() public onlyOwner {
        assembly {
            let counterSlot := sload(_counter.slot)
            sstore(_counter.slot, add(counterSlot, 1))
        }
        emit CounterUpdated(owner, _counter);
    }

    function getCounter() public view returns (uint256) {
        return _counter;
    }
}
```

